     * @param orderBy Sorting field (must be a valid column name from whitelist)
     * @param sortDirection Sorting direction (ASC or DESC, case-insensitive)
     * @return List of users sorted by the specified field and direction
     */
    public List<User> getUsersByOrder(String orderBy, String sortDirection) {
        String validatedOrderBy = validateOrderBy(orderBy);
        String validatedSortDirection = validateSortDirection(sortDirection);

        return userMapper.getUsersByOrder(validatedOrderBy, validatedSortDirection);
    }

    /**
     * Get all users.
     * @return List of all users
     */
    public List<User> getAllUsers() {
        return userMapper.getAllUsers();
    }

    /**
     * Validate and sanitize the orderBy parameter.
     * Returns a valid column name from the whitelist or the default column.
     * 
     * @param orderBy the column name to sort by
     * @return validated column name from whitelist
     */
    private String validateOrderBy(String orderBy) {
        if (orderBy == null || orderBy.trim().isEmpty()) {
            return DEFAULT_ORDER_BY;
        }

        String trimmedOrderBy = orderBy.trim();

        // Check against whitelist to prevent SQL injection
        if (VALID_ORDER_COLUMNS.contains(trimmedOrderBy)) {
            return trimmedOrderBy;
        }

        // Return default if invalid - do not expose validation failure details
        return DEFAULT_ORDER_BY;
